+
+        // The trailing `\n` from the first push is held until we know whether
+        // `</think>` follows.
+        let first = parser.push("<think>reason\n").unwrap();
+        assert_eq!(first.reasoning.as_deref(), Some("reason"));
+        assert_eq!(first.content, None);
